local Sound = {
    Cache = {};
    ShootSounds = {};
    HitSounds = {};
};

local BASE64 = crypt and crypt.base64 or base64;
local TableSort = table.sort;
local StringChar = string.char;
local MathFloor = math.floor;
local MathClamp = math.clamp or function(Value, Min, Max)
    if Value < Min then
        return Min
    end
    if Value > Max then
        return Max
    end
    return Value
end;

Sound.__index = Sound;

local Directory = _G.Directory;

local ShootSoundList = {
    ["Scar20"] = "91510933153450",
    ["SSg08"] = "2476571739",
    ["AWP"] = "2753888131",
    ["AK47-CS:GO"] = "2476570846",
    ["G3SG1"] = "18512294165",
