    ["SKS"] = "8660502251",
    ["SKS-Silenced"] = "8660503874",
    ["FiveSeven"] = "9057668558",
    ["AK47-Tarkov"] = "122655160661494",
    ["AK47-Rust"] = "7011577038",
    ["Arrow"] = "76555891505373",
};

local HitSoundList = {
    ['Niggahack'] = "";
    ["Minecraft"] = "";
    ["Rust"] = "";
