function Sound:Decode(Base64: string)
    return BASE64.decode(Base64)
end;

function Sound:DetectExtension(Data: any)
    if type(Data) ~= "string" then
        return "mp3"
    end;

    local Head4 = Data:sub(1, 4);
    if Head4 == "RIFF" then
        return "wav"
    end;
    if Head4 == "OggS" then
        return "ogg"
    end;

    local Head3 = Data:sub(1, 3);
    if Head3 == "ID3" then
        return "mp3"
    end;

    local b1 = Data:byte(1);
    local b2 = Data:byte(2);
    if b1 == 0xFF and b2 and b2 >= 0xE0 then
        return "mp3"
    end;

    return "mp3"
end;

local function readUInt16(Data, Index)
    local B1, B2 = Data:byte(Index, Index + 1);
    if not B2 then
        return
    end;
    return B1 + B2 * 256
end;

local function readUInt32(Data, Index)
    local B1, B2, B3, B4 = Data:byte(Index, Index + 3);
    if not B4 then
        return
    end;
    return B1 + B2 * 256 + B3 * 65536 + B4 * 16777216
end;

local function writeUInt16(Value)
    return StringChar(
        Value % 256,
        MathFloor(Value / 256) % 256
    )
end;

local function writeUInt32(Value)
    return StringChar(
        Value % 256,
        MathFloor(Value / 256) % 256,
        MathFloor(Value / 65536) % 256,
        MathFloor(Value / 16777216) % 256
    )
end;

local function floatToPcm16(Data, Index)
    local Bits = readUInt32(Data, Index);
    if not Bits then
        return 0
    end;

    local Sign = 1;
    if Bits >= 0x80000000 then
        Sign = -1;
        Bits = Bits - 0x80000000;
    end;

    local Exponent = MathFloor(Bits / 0x800000) % 0x100;
    local Mantissa = Bits % 0x800000;

    local Value;
    if Exponent == 255 then
        Value = Sign;
    elseif Exponent == 0 then
        if Mantissa == 0 then
            Value = 0;
        else
            Value = Sign * (Mantissa / 0x800000) * 2^-126;
        end
    else
        Value = Sign * (1 + Mantissa / 0x800000) * 2^(Exponent - 127);
    end;

    local Sample = MathFloor(MathClamp(Value, -1, 1) * 32767 + (Value >= 0 and 0.5 or -0.5));
    if Sample < 0 then
        Sample = Sample + 0x10000;
    end;

    return Sample
end;

function Sound:NormalizeWav(Data)
    if type(Data) ~= "string" or Data:sub(1, 4) ~= "RIFF" or Data:sub(9, 12) ~= "WAVE" then
        return Data
    end;

    local Index = 13;
    local Format;
    local Channels;
    local SampleRate;
    local DataChunkStart;
    local DataChunkSize;

    while Index + 7 <= #Data do
        local ChunkId = Data:sub(Index, Index + 3);
        local ChunkSize = readUInt32(Data, Index + 4);
        if not ChunkSize then
            break
        end;

        local ChunkDataStart = Index + 8;
        if ChunkId == "fmt " then
            Format = readUInt16(Data, ChunkDataStart);
            Channels = readUInt16(Data, ChunkDataStart + 2);
            SampleRate = readUInt32(Data, ChunkDataStart + 4);
        elseif ChunkId == "data" then
            DataChunkStart = ChunkDataStart;
            DataChunkSize = ChunkSize;
            break
        end;

        Index = ChunkDataStart + ChunkSize + (ChunkSize % 2);
    end;

    if Format ~= 3 or not Channels or not SampleRate or not DataChunkStart or not DataChunkSize then
        return Data
    end;

    local Samples = table.create(MathFloor(DataChunkSize / 2));
    local SampleIndex = 1;
    local DataChunkEnd = DataChunkStart + DataChunkSize - 1;
    for Offset = DataChunkStart, DataChunkEnd, 4 do
        Samples[SampleIndex] = writeUInt16(floatToPcm16(Data, Offset));
        SampleIndex = SampleIndex + 1;
    end;

    local PcmData = table.concat(Samples);
    local ByteRate = SampleRate * Channels * 2;
    local BlockAlign = Channels * 2;
    local DataSize = #PcmData;

    return table.concat({
        "RIFF",
        writeUInt32(36 + DataSize),
        "WAVE",
        "fmt ",
        writeUInt32(16),
        writeUInt16(1),
        writeUInt16(Channels),
        writeUInt32(SampleRate),
        writeUInt32(ByteRate),
        writeUInt16(BlockAlign),
        writeUInt16(16),
        "data",
        writeUInt32(DataSize),
        PcmData,
    })
end;

function Sound:Write(Name: string, Data: any)
    Data = self:NormalizeWav(Data);
    local Ext = self:DetectExtension(Data);
    local Path = Directory.Sound.."/"..Name.."."..Ext;
    writefile(Path, Data);
    return Path
end;

function Sound:AddShootSound(Name: string, ID: string, Base64: boolean)
    local Existing = self.ShootSounds[Name]
    if Existing then
        return Existing
    end;

    if Base64 then
        local Decode = self:Decode(ID)
        local FormattedID = getcustomasset(self:Write(Name, Decode));

        self.ShootSounds[Name] = FormattedID;
        return self.ShootSounds[Name]
    end;

    self.ShootSounds[Name] = ("rbxassetid://%s"):format(ID);
    return self.ShootSounds[Name];
end;

function Sound:AddHitSound(Name: string, ID: string, Base64: boolean)
    local Existing = self.HitSounds[Name]
    if Existing then
        return Existing
    end;

    if Base64 then
        local Decode = self:Decode(ID)
        local FormattedID = getcustomasset(self:Write(Name, Decode));

        self.HitSounds[Name] = FormattedID;
        return self.HitSounds[Name];
    end;

    self.HitSounds[Name] = ("rbxassetid://%s"):format(ID);
    return self.HitSounds[Name];
end;

function Sound:GetHitSound(Name: string)
    return self.HitSounds[Name];
end;

function Sound:GetShootSound(Name: string)
    return self.ShootSounds[Name];
end;

function Sound:GetHitSoundNames()
    local Names = {};
    for Name in pairs(self.HitSounds) do
        Names[#Names + 1] = Name;
    end;
    TableSort(Names);
    return Names
end;

function Sound:GetShootSoundNames()
    local Names = {};
    for Name in pairs(self.ShootSounds) do
        Names[#Names + 1] = Name;
    end;
    TableSort(Names);
    return Names
end;

for Name, Base64 in pairs(HitSoundList) do
    Sound:AddHitSound(Name, Base64, true);
end;

for Name, AssetNum in pairs(ShootSoundList) do
    Sound:AddShootSound(Name, AssetNum, false);
end;


_G.Sound = Sound;
_G.Sounds = Sound;
return Sound;
